# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory backend for managing users, projects, tasks,
messaging, performance dashboards, and reporting.

The public surface (classes, enums, exceptions and the
``TeamCollaborationManager`` facade) is exercised by ``test_solution.py``.
Only the Python standard library is used.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Dict, List, Optional


# ---------------------------------------------------------------------------
# Sentinel used to distinguish "argument not provided" from an explicit None.
# ---------------------------------------------------------------------------
_UNSET = object()


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle status of a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Role of a registered user."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    """Supported export formats for reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Identifies the kind of report payload produced by the manager."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when supplied input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Domain models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A registered member of the collaboration workspace."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A project owned by a user with a scheduled date range."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime


@dataclass
class Task:
    """A unit of work belonging to a project."""

    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Message:
    """A message posted against a project or a task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """A peer rating left by one user about another."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Repository -- a thin, lock-sharing container for a single entity type.
# ---------------------------------------------------------------------------
class _Repository:
    """In-memory store for one entity type.

    All repositories created by a manager share the *same* lock object so a
    single critical section can guard a multi-entity operation.
    """

    def __init__(self, lock):
        self._lock = lock
        self._items = {}


# ---------------------------------------------------------------------------
# Manager facade
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Thread-safe in-memory team collaboration backend."""

    def __init__(self, now=None):
        # ``now`` is a zero-argument callable returning the current datetime.
        self._now = now if now is not None else datetime.now
        self._lock = threading.RLock()
        self._id_counter = 0

        # All repositories share the single manager lock.
        self.users = _Repository(self._lock)
        self.projects = _Repository(self._lock)
        self.tasks = _Repository(self._lock)
        self.messages = _Repository(self._lock)
        self.performance = _Repository(self._lock)  # stores Rating entities
        self.reports = _Repository(self._lock)

    # ------------------------------------------------------------------
    # Internal helpers
    # ------------------------------------------------------------------
    def _next_id(self):
        self._id_counter += 1
        return self._id_counter

    @staticmethod
    def _clone(obj):
        """Return a deep copy so callers cannot mutate stored state."""
        return copy.deepcopy(obj)

    @staticmethod
    def _validate_username(username):
        if not isinstance(username, str) or not username.strip():
            raise ValidationError("username must be a non-empty string")
        return username.strip()

    @staticmethod
    def _validate_email(email):
        if not isinstance(email, str):
            raise ValidationError("email must be a string")
        cleaned = email.strip()
        if not cleaned or "@" not in cleaned:
            raise ValidationError("email must be non-empty and contain '@'")
        return cleaned

    def _find_user_by_username(self, username, exclude_id=None):
        target = username.strip().lower()
        for user in self.users._items.values():
            if user.id == exclude_id:
                continue
            if user.username.lower() == target:
                return user
        return None

    def _find_user_by_email(self, email, exclude_id=None):
        target = email.strip().lower()
        for user in self.users._items.values():
            if user.id == exclude_id:
                continue
            if user.email.lower() == target:
                return user
        return None

    def _require_user(self, user_id):
        user = self.users._items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user

    def _require_project(self, project_id):
        project = self.projects._items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project

    def _require_task(self, task_id):
        task = self.tasks._items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task

    def _require_message(self, message_id):
        message = self.messages._items.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message

    # ==================================================================
    # User management
    # ==================================================================
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            username = self._validate_username(username)
            email = self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            if self._find_user_by_username(username) is not None:
                raise DuplicateError("username already in use")
            if self._find_user_by_email(email) is not None:
                raise DuplicateError("email already in use")

            user = User(
                id=self._next_id(),
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users._items[user.id] = user
            return self._clone(user)

    def get_user(self, user_id):
        with self._lock:
            return self._clone(self._require_user(user_id))

    def list_users(self):
        with self._lock:
            users = sorted(self.users._items.values(), key=lambda u: u.id)
            return [self._clone(u) for u in users]

    def update_user(self, user_id, username=_UNSET, email=_UNSET, role=_UNSET):
        with self._lock:
            user = self._require_user(user_id)

            if username is not _UNSET:
                new_username = self._validate_username(username)
                if self._find_user_by_username(new_username, exclude_id=user_id):
                    raise DuplicateError("username already in use")
                user.username = new_username

            if email is not _UNSET:
                new_email = self._validate_email(email)
                if self._find_user_by_email(new_email, exclude_id=user_id):
                    raise DuplicateError("email already in use")
                user.email = new_email

            if role is not _UNSET:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                user.role = role

            return self._clone(user)

    def delete_user(self, user_id):
        with self._lock:
            self._require_user(user_id)

            for project in self.projects._items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")

            for task in self.tasks._items.values():
                if task.assignee_id == user_id and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has an open task assigned")

            del self.users._items[user_id]

    # ==================================================================
    # Project management
    # ==================================================================
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name must be non-empty")
            self._require_user(owner_id)
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")

            project = Project(
                id=self._next_id(),
                name=name.strip(),
                description=description or "",
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
            )
            self.projects._items[project.id] = project
            return self._clone(project)

    def get_project(self, project_id):
        with self._lock:
            return self._clone(self._require_project(project_id))

    def list_projects(self):
        with self._lock:
            projects = sorted(self.projects._items.values(), key=lambda p: p.id)
            return [self._clone(p) for p in projects]

    def update_project(
        self,
        project_id,
        name=_UNSET,
        description=_UNSET,
        start_date=_UNSET,
        end_date=_UNSET,
    ):
        with self._lock:
            project = self._require_project(project_id)

            new_start = project.start_date if start_date is _UNSET else start_date
            new_end = project.end_date if end_date is _UNSET else end_date
            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")

            if name is not _UNSET:
                if not isinstance(name, str) or not name.strip():
                    raise ValidationError("project name must be non-empty")
                project.name = name.strip()

            if description is not _UNSET:
                project.description = description or ""

            if start_date is not _UNSET:
                project.start_date = start_date
            if end_date is not _UNSET:
                project.end_date = end_date

            return self._clone(project)

    def delete_project(self, project_id):
        with self._lock:
            self._require_project(project_id)

            task_ids = {
                tid
                for tid, task in self.tasks._items.items()
                if task.project_id == project_id
            }
            for tid in task_ids:
                del self.tasks._items[tid]

            message_ids = [
                mid
                for mid, msg in self.messages._items.items()
                if msg.project_id == project_id or msg.task_id in task_ids
            ]
            for mid in message_ids:
                del self.messages._items[mid]

            del self.projects._items[project_id]

    # ==================================================================
    # Task management
    # ==================================================================
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = self._require_project(project_id)
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title must be non-empty")
            if assignee_id is not None:
                self._require_user(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start")

            task = Task(
                id=self._next_id(),
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self.tasks._items[task.id] = task
            return self._clone(task)

    def get_task(self, task_id):
        with self._lock:
            return self._clone(self._require_task(task_id))

    def list_tasks_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tasks = sorted(
                (
                    t
                    for t in self.tasks._items.values()
                    if t.project_id == project_id
                ),
                key=lambda t: t.id,
            )
            return [self._clone(t) for t in tasks]

    def list_tasks_by_assignee(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = sorted(
                (
                    t
                    for t in self.tasks._items.values()
                    if t.assignee_id == user_id
                ),
                key=lambda t: t.id,
            )
            return [self._clone(t) for t in tasks]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(assignee_id)
            task.assignee_id = assignee_id
            return self._clone(task)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            task = self._require_task(task_id)
            self._require_user(new_assignee_id)
            task.assignee_id = new_assignee_id
            return self._clone(task)

    def unassign_task(self, task_id):
        with self._lock:
            task = self._require_task(task_id)
            task.assignee_id = None
            return self._clone(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self._require_task(task_id)
            if deadline is not None:
                project = self.projects._items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline must not precede project start")
            task.deadline = deadline
            return self._clone(task)

    def update_status(self, task_id, status):
        if not isinstance(status, TaskStatus):
            raise ValidationError("status must be a TaskStatus")
        with self._lock:
            task = self._require_task(task_id)
            now = self._now()

            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now

            task.status = status
            return self._clone(task)

    # ==================================================================
    # Messaging
    # ==================================================================
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ):
        with self._lock:
            has_project = project_id is not None
            has_task = task_id is not None
            if has_project == has_task:
                raise ValidationError(
                    "exactly one of project_id or task_id is required"
                )

            self._require_user(author_id)
            if has_project:
                self._require_project(project_id)
            else:
                self._require_task(task_id)

            if parent_id is not None:
                self._require_message(parent_id)

            attachment_objs = self._build_attachments(author_id, attachments)

            if (not isinstance(body, str) or not body.strip()) and not attachment_objs:
                raise ValidationError(
                    "message body required when there are no attachments"
                )

            message = Message(
                id=self._next_id(),
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=self._now(),
                edited_at=None,
            )
            self.messages._items[message.id] = message
            return self._clone(message)

    def _build_attachments(self, author_id, attachments):
        result = []
        if not attachments:
            return result
        now = self._now()
        for entry in attachments:
            filename, data = entry
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("attachment filename must be non-empty")
            result.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
            )
        return result

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            if (not isinstance(new_body, str) or not new_body.strip()) and not message.attachments:
                raise ValidationError(
                    "message body required when there are no attachments"
                )
            message.body = new_body
            message.edited_at = self._now()
            return self._clone(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError(
                    "only the author may attach to this message"
                )
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("attachment filename must be non-empty")
            message.attachments.append(
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=uploader_id,
                    uploaded_at=self._now(),
                )
            )
            return self._clone(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            self._require_project(project_id)
            messages = sorted(
                (
                    m
                    for m in self.messages._items.values()
                    if m.project_id == project_id
                ),
                key=lambda m: m.id,
            )
            return [self._clone(m) for m in messages]

    def list_messages_by_task(self, task_id):
        with self._lock:
            self._require_task(task_id)
            messages = sorted(
                (
                    m
                    for m in self.messages._items.values()
                    if m.task_id == task_id
                ),
                key=lambda m: m.id,
            )
            return [self._clone(m) for m in messages]

    def delete_message(self, message_id, requester_id):
        with self._lock:
            message = self._require_message(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError(
                    "only the author may delete this message"
                )
            del self.messages._items[message_id]

    # ==================================================================
    # Performance dashboard
    # ==================================================================
    def _tasks_for_user(self, user_id, project_id=None):
        return [
            t
            for t in self.tasks._items.values()
            if t.assignee_id == user_id
            and (project_id is None or t.project_id == project_id)
        ]

    def _ratings_for_user(self, user_id):
        return [
            r
            for r in self.performance._items.values()
            if r.ratee_id == user_id
        ]

    def get_completion_rate(self, user_id):
        with self._lock:
            self._require_user(user_id)
            tasks = self._tasks_for_user(user_id)
            if not tasks:
                return 0.0
            completed = sum(
                1 for t in tasks if t.status == TaskStatus.COMPLETED
            )
            return completed / len(tasks)

    def get_average_completion_time(self, user_id):
        with self._lock:
            self._require_user(user_id)
            durations = [
                (t.completed_at - t.started_at).total_seconds()
                for t in self._tasks_for_user(user_id)
                if t.status == TaskStatus.COMPLETED
                and t.completed_at is not None
                and t.started_at is not None
            ]
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            self._require_user(rater_id)
            self._require_user(ratee_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer in [1, 5]")
            if score < 1 or score > 5:
                raise ValidationError("score must be in [1, 5]")
            if task_id is not None:
                self._require_task(task_id)

            rating = Rating(
                id=self._next_id(),
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback or "",
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance._items[rating.id] = rating
            return self._clone(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            self._require_user(user_id)
            ratings = sorted(
                self._ratings_for_user(user_id), key=lambda r: r.id
            )
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [self._clone(r) for r in ratings],
            }

    def _compute_user_stats(self, user_id, project_id=None):
        user = self.users._items.get(user_id)
        username = user.username if user is not None else None
        tasks = self._tasks_for_user(user_id, project_id)
        total = len(tasks)
        completed = [t for t in tasks if t.status == TaskStatus.COMPLETED]
        in_progress = [t for t in tasks if t.status == TaskStatus.IN_PROGRESS]
        not_started = [t for t in tasks if t.status == TaskStatus.NOT_STARTED]

        completion_rate = (len(completed) / total) if total else 0.0
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in completed
            if t.completed_at is not None and t.started_at is not None
        ]
        avg_time = (sum(durations) / len(durations)) if durations else None

        ratings = self._ratings_for_user(user_id)
        rating_count = len(ratings)
        rating_average = (
            sum(r.score for r in ratings) / rating_count
            if rating_count
            else 0.0
        )

        return {
            "user_id": user_id,
            "username": username,
            "total_tasks": total,
            "completed_tasks": len(completed),
            "in_progress_tasks": len(in_progress),
            "not_started_tasks": len(not_started),
            "completion_rate": completion_rate,
            "average_completion_time": avg_time,
            "rating_count": rating_count,
            "rating_average": rating_average,
        }

    def get_user_dashboard(self, user_id):
        with self._lock:
            self._require_user(user_id)
            return self._compute_user_stats(user_id)

    # ==================================================================
    # Reports
    # ==================================================================
    def project_progress_report(self, project_id):
        with self._lock:
            self._require_project(project_id)
            tasks = [
                t
                for t in self.tasks._items.values()
                if t.project_id == project_id
            ]
            total = len(tasks)

            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1

            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = (completed / total) if total else 0.0

            now = self._now()
            overdue = sum(
                1
                for t in tasks
                if t.deadline is not None
                and t.deadline < now
                and t.status != TaskStatus.COMPLETED
            )

            per_assignee = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id,
                    {
                        "total": 0,
                        "completed": 0,
                        "in_progress": 0,
                        "not_started": 0,
                    },
                )
                bucket["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed"] += 1
                elif task.status == TaskStatus.IN_PROGRESS:
                    bucket["in_progress"] += 1
                else:
                    bucket["not_started"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None:
                self._require_project(project_id)

            tasks = [
                t
                for t in self.tasks._items.values()
                if project_id is None or t.project_id == project_id
            ]
            user_ids = sorted(
                {t.assignee_id for t in tasks if t.assignee_id is not None}
            )
            rows = [
                self._compute_user_stats(uid, project_id) for uid in user_ids
            ]

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            self._require_user(user_id)
            stats = self._compute_user_stats(user_id)
            tasks = sorted(
                self._tasks_for_user(user_id), key=lambda t: t.id
            )
            report = dict(stats)
            report["report_type"] = ReportType.INDIVIDUAL_PERFORMANCE.value
            report["tasks"] = [self._clone(t) for t in tasks]
            return report

    # ------------------------------------------------------------------
    # Report export
    # ------------------------------------------------------------------
    def export_report(self, report, fmt):
        if not isinstance(report, dict):
            raise ValidationError("report must be a dict")
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")

        if fmt == ReportFormat.CSV:
            return self._report_to_csv(report)
        return self._report_to_pdf(report)

    @staticmethod
    def _scalar(value):
        if value is None or isinstance(value, (str, int, float, bool)):
            return value
        return str(value)

    def _report_to_csv(self, report):
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        report_type = report.get("report_type")

        if report_type == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "in_progress_tasks",
                "not_started_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            writer.writerow(header)
            for row in report.get("rows", []):
                writer.writerow([self._scalar(row.get(key, "")) for key in header])

        elif report_type == ReportType.PROJECT_PROGRESS.value:
            writer.writerow(["metric", "value"])
            writer.writerow(["project_id", self._scalar(report.get("project_id"))])
            writer.writerow(["total_tasks", report.get("total_tasks", 0)])
            writer.writerow(
                ["completion_rate", report.get("completion_rate", 0.0)]
            )
            writer.writerow(["overdue_tasks", report.get("overdue_tasks", 0)])
            for status, count in report.get("status_counts", {}).items():
                writer.writerow(["status_" + str(status), count])

        elif report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            keys = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "in_progress_tasks",
                "not_started_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            writer.writerow(["metric", "value"])
            for key in keys:
                writer.writerow([key, self._scalar(report.get(key, ""))])

        else:
            writer.writerow(["key", "value"])
            for key, value in report.items():
                if value is None or isinstance(value, (str, int, float, bool)):
                    writer.writerow([key, value])

        return buffer.getvalue()

    def _report_to_pdf(self, report):
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if value is None or isinstance(value, (str, int, float, bool)):
                lines.append("{0}: {1}".format(key, value))
            elif isinstance(value, dict):
                lines.append("{0}:".format(key))
                for sub_key, sub_value in value.items():
                    lines.append("  {0}: {1}".format(sub_key, sub_value))
            elif isinstance(value, list):
                lines.append("{0}: {1} item(s)".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, value))
        return _build_pdf(lines)


# ---------------------------------------------------------------------------
# Minimal PDF writer (standard library only).
# ---------------------------------------------------------------------------
def _build_pdf(lines):
    """Build a minimal, structurally valid single-page PDF document."""

    def escape(text):
        return (
            text.replace("\\", "\\\\")
            .replace("(", "\\(")
            .replace(")", "\\)")
        )

    content_parts = ["BT", "/F1 12 Tf", "50 750 Td", "14 TL"]
    first = True
    for line in lines:
        rendered = escape(str(line))
        if first:
            content_parts.append("({0}) Tj".format(rendered))
            first = False
        else:
            content_parts.append("T*")
            content_parts.append("({0}) Tj".format(rendered))
    content_parts.append("ET")
    content = "\n".join(content_parts).encode("latin-1", "replace")

    objects = [
        b"<< /Type /Catalog /Pages 2 0 R >>",
        b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
        (
            b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
            b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>"
        ),
        b"<< /Length "
        + str(len(content)).encode("ascii")
        + b" >>\nstream\n"
        + content
        + b"\nendstream",
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
    ]

    pdf = bytearray(b"%PDF-1.4\n")
    offsets = []
    for index, body in enumerate(objects, start=1):
        offsets.append(len(pdf))
        pdf += str(index).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

    xref_position = len(pdf)
    count = len(objects) + 1
    pdf += b"xref\n0 " + str(count).encode("ascii") + b"\n"
    pdf += b"0000000000 65535 f \n"
    for offset in offsets:
        pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
    pdf += b"trailer\n<< /Size " + str(count).encode("ascii") + b" /Root 1 0 R >>\n"
    pdf += b"startxref\n" + str(xref_position).encode("ascii") + b"\n%%EOF"
    return bytes(pdf)


